import{_ as t,o as a,c as r,ah as o}from"./chunks/framework.C8Zd3T50.js";const u=JSON.parse('{"title":"What About Telegram?","description":"","frontmatter":{},"headers":[],"relativePath":"whatabout/telegram.md","filePath":"whatabout/telegram.md"}'),s={name:"whatabout/telegram.md"};function n(i,e,l,h,c,d){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="what-about-telegram" tabindex="-1">What About Telegram? <a class="header-anchor" href="#what-about-telegram" aria-label="Permalink to &quot;What About Telegram?&quot;">​</a></h1><p>Telegram has over 950 million users and is frequently described in the press as an &quot;encrypted messaging app.&quot; This description is, to put it charitably, misleading.</p><h2 id="encryption-is-not-the-default" tabindex="-1">Encryption Is Not the Default <a class="header-anchor" href="#encryption-is-not-the-default" aria-label="Permalink to &quot;Encryption Is Not the Default&quot;">​</a></h2><p>Telegram&#39;s regular chats — the ones everyone uses — are not end-to-end encrypted. They use client-server encryption, which means Telegram&#39;s servers hold the decryption keys and can read message content.<sup class="footnote-ref"><a href="#fn1" id="fnref1">[1]</a></sup></p><p>E2E encryption is available only through &quot;Secret Chats,&quot; which must be manually activated for each conversation. Secret Chats are limited to one-on-one conversations — group chats cannot be end-to-end encrypted at all. The UX for activating Secret Chats is, as cryptographer Matthew Green has noted, &quot;oddly difficult for non-expert users.&quot;<sup class="footnote-ref"><a href="#fn2" id="fnref2">[2]</a></sup></p><p>The practical result is that the vast majority of Telegram conversations — and every single group chat — are readable by Telegram&#39;s servers.</p><h2 id="homegrown-cryptography" tabindex="-1">Homegrown Cryptography <a class="header-anchor" href="#homegrown-cryptography" aria-label="Permalink to &quot;Homegrown Cryptography&quot;">​</a></h2><p>Telegram uses MTProto, a custom cryptographic protocol designed in-house rather than building on established standards like TLS or the Signal Protocol. This is a red flag in applied cryptography — the field has learned, painfully, that designing your own crypto protocol is almost always a mistake.</p><p>Peer-reviewed security analyses have identified concrete vulnerabilities in MTProto: both versions 1.0 and 2.0 have IND-CPA weaknesses, and the protocol does not satisfy standard definitions of authenticated encryption.<sup class="footnote-ref"><a href="#fn3" id="fnref3">[3]</a></sup> Green&#39;s assessment of MTProto&#39;s use of IGE (Infinite Garble Extension), a non-standard cipher mode, was blunt: &quot;The crypto is like being stabbed in the eye with a fork.&quot;</p><h2 id="server-is-closed-source" tabindex="-1">Server Is Closed Source <a class="header-anchor" href="#server-is-closed-source" aria-label="Permalink to &quot;Server Is Closed Source&quot;">​</a></h2><p>Telegram&#39;s server code is proprietary and has never been published. The client apps are open source under GPL v2/v3, but the server — the part that actually handles your messages and holds the encryption keys for non-Secret-Chat conversations — is a black box.</p><p>Telegram has argued that publishing server code provides no security benefit since there is no way to verify that published code matches what runs on their servers. This argument is technically correct but strategically self-serving: it is an argument against transparency itself, not a justification for opacity.</p><h2 id="phone-number-required" tabindex="-1">Phone Number Required <a class="header-anchor" href="#phone-number-required" aria-label="Permalink to &quot;Phone Number Required&quot;">​</a></h2><p>Telegram requires a phone number for registration. There is a workaround involving anonymous blockchain-based phone numbers purchased through Telegram&#39;s Fragment platform, but this is a cryptocurrency transaction, not a practical alternative for most users.</p><h2 id="metadata-collection" tabindex="-1">Metadata Collection <a class="header-anchor" href="#metadata-collection" aria-label="Permalink to &quot;Metadata Collection&quot;">​</a></h2><p>Telegram collects and retains IP addresses, device information, phone numbers, contact lists, and interaction timestamps for up to 12 months. This data can be shared with authorities if legally required.</p><h2 id="the-durov-arrest" tabindex="-1">The Durov Arrest <a class="header-anchor" href="#the-durov-arrest" aria-label="Permalink to &quot;The Durov Arrest&quot;">​</a></h2><p>In August 2024, Telegram CEO Pavel Durov was arrested at Paris-Le Bourget Airport and indicted on 12 charges related to Telegram&#39;s platform governance. Whatever one thinks of the legal merits, the episode illustrates the risks of a centralized, personality-driven platform: a single arrest created existential uncertainty for a service used by nearly a billion people.</p><h2 id="what-telegram-gets-right" tabindex="-1">What Telegram Gets Right <a class="header-anchor" href="#what-telegram-gets-right" aria-label="Permalink to &quot;What Telegram Gets Right&quot;">​</a></h2><ul><li>The UX is polished and the feature set is extensive.</li><li>The platform has demonstrated willingness to resist government pressure in some jurisdictions.</li><li>Client-side code is open source.</li><li>The scale demonstrates demand for messaging outside Big Tech.</li></ul><p>But Telegram is not an encrypted messaging platform in any meaningful sense. It is a cloud messaging platform with an optional, limited encryption feature that most users never activate. By os384&#39;s criteria, it fails on privacy (phone number required, metadata collected), on security (E2E not default, homegrown crypto), on open source (server is closed), and on sovereignty (centralized, single point of control).</p><hr class="footnotes-sep"><section class="footnotes"><ol class="footnotes-list"><li id="fn1" class="footnote-item"><p>See <a href="https://core.telegram.org/api/end-to-end" target="_blank" rel="noreferrer">Telegram&#39;s own documentation on Secret Chats</a>: E2E encryption is explicitly described as a separate, opt-in feature. <a href="#fnref1" class="footnote-backref">↩︎</a></p></li><li id="fn2" class="footnote-item"><p>Matthew Green, quoted in <a href="https://www.schneier.com/blog/archives/2024/08/matthew-green-on-telegrams-encryption.html" target="_blank" rel="noreferrer">Schneier on Security</a>, August 2024. <a href="#fnref2" class="footnote-backref">↩︎</a></p></li><li id="fn3" class="footnote-item"><p>See Albrecht et al., <a href="https://eprint.iacr.org/2025/451.pdf" target="_blank" rel="noreferrer">&quot;Four Attacks and a Proof for Telegram,&quot;</a> and the earlier <a href="https://eprint.iacr.org/2015/1177.pdf" target="_blank" rel="noreferrer">CCA analysis of MTProto</a>. <a href="#fnref3" class="footnote-backref">↩︎</a></p></li></ol></section>',23)])])}const f=t(s,[["render",n]]);export{u as __pageData,f as default};
